class Solution:
    def minimumIndex(self, nums: List[int]) -> int:
        # Step 1: Find the dominant element
        dominant = None
        count = 0
        for num in nums:
            if count == 0:
                dominant = num
            if num == dominant:
                count += 1
            else:
                count -= 1

        # Step 2: Count total occurrences of the dominant element
        total_count = 0
        for num in nums:
            if num == dominant:
                total_count += 1

        # Step 3: Iterate through the array and check for valid splits
        left_count = 0
        for i in range(len(nums)):
            if nums[i] == dominant:
                left_count += 1
            # Check if both subarrays have dominant as their dominant
            if (left_count * 2 > (i + 1)) and ((total_count - left_count) * 2 > (len(nums) - (i + 1))):
                return i

        return -1
